#!/usr/bin/env bash
set -euo pipefail

TASK_FILE="/app/tasks.txt"

usage() {
  cat <<'USAGE'
Usage:
  todo.sh add <task>
  todo.sh list
  todo.sh done <number>
USAGE
}

cmd=${1-}
case "$cmd" in
  add)
    shift || true
    [ $# -ge 1 ] || { usage >&2; exit 1; }
    task="$*"
    printf '%s\n' "$task" >> "$TASK_FILE"
    ;;
  list)
    [ -f "$TASK_FILE" ] && nl -ba "$TASK_FILE" || true
    ;;
  done)
    shift || true
    [ $# -eq 1 ] || { usage >&2; exit 1; }
    n="$1"
    [[ "$n" =~ ^[0-9]+$ ]] && [ "$n" -gt 0 ] || { echo "Invalid task number: $n" >&2; exit 1; }
    [ -f "$TASK_FILE" ] || { echo "No tasks." >&2; exit 1; }
    total=$(wc -l < "$TASK_FILE" | tr -d ' ')
    [ "$n" -le "$total" ] || { echo "Task number out of range." >&2; exit 1; }
    tmp="${TASK_FILE}.tmp$$"
    awk -v n="$n" 'NR!=n' "$TASK_FILE" > "$tmp"
    mv "$tmp" "$TASK_FILE"
    ;;
  ''|-h|--help|help)
    usage
    ;;
  *)
    usage >&2
    exit 1
    ;;
esac

