set -e
file=/doc/README.md
awk '
function anchor(s,   t){
  t=tolower(s)
  gsub(/[[:space:]]+/,"-",t)
  return t
}
BEGIN{first=-1}
{
  lines[NR]=$0
  if($0 ~ /^# / && first==-1){first=NR; firstTitle=substr($0,3)}
  if($0 ~ /^#{1,2} /){
    level = ($0 ~ /^## /) ? 2 : 1
    title = substr($0, level+2)
    if(title!=""){
      hN++
      hLevel[hN]=level
      hTitle[hN]=title
    }
  }
}
END{
  if(first==-1){print "No top-level heading found" > "/dev/stderr"; exit 1}
  # output up to first heading
  for(i=1;i<=first;i++) print lines[i]
  print ""
  # TOC lines (skip first heading itself)
  for(i=1;i<=hN;i++){
    if(hLevel[i]==1 && hTitle[i]==firstTitle) continue
    indent = (hLevel[i]==2) ? "  " : ""
    printf "%s- [%s](#%s)\n", indent, hTitle[i], anchor(hTitle[i])
  }
  print ""
  for(i=first+1;i<=NR;i++) print lines[i]
}
' "$file" > /tmp/README.md && mv /tmp/README.md "$file"

